"use client";

import React, { createContext, useContext, useState, useCallback, ReactNode } from "react";
import * as fabric from "fabric";

type TabType = "select" | "text" | "image" | "shape" | "ai" | "layers";

interface EditorContextType {
  canvas: fabric.Canvas | null;
  setCanvas: (canvas: fabric.Canvas | null) => void;
  selectedObject: fabric.FabricObject | null;
  setSelectedObject: (obj: fabric.FabricObject | null) => void;
  activeTab: TabType;
  setActiveTab: (tab: TabType) => void;
  addText: (text: string, options?: any) => void;
  addImage: (url: string) => void;
}

const EditorContext = createContext<EditorContextType | undefined>(undefined);

export function EditorProvider({ children }: { children: ReactNode }) {
  const [canvas, setCanvas] = useState<fabric.Canvas | null>(null);
  const [selectedObject, setSelectedObject] = useState<fabric.FabricObject | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>("select");

  const addText = useCallback((text: string, options = {}) => {
    if (!canvas) return;
    const fabricText = new fabric.FabricText(text, {
      left: 100,
      top: 100,
      fontSize: 32,
      fill: "#000000",
      ...options
    });
    canvas.add(fabricText);
    canvas.setActiveObject(fabricText);
    canvas.renderAll();
  }, [canvas]);

  const addImage = useCallback((url: string) => {
    if (!canvas) return;
    fabric.FabricImage.fromURL(url).then((img) => {
      img.scaleToWidth(200);
      canvas.add(img);
      canvas.setActiveObject(img);
      canvas.renderAll();
    });
  }, [canvas]);

  return (
    <EditorContext.Provider 
      value={{ 
        canvas, 
        setCanvas, 
        selectedObject, 
        setSelectedObject,
        activeTab,
        setActiveTab,
        addText,
        addImage
      }}
    >
      {children}
    </EditorContext.Provider>
  );
}

export function useEditor() {
  const context = useContext(EditorContext);
  if (context === undefined) {
    throw new Error("useEditor must be used within an EditorProvider");
  }
  return context;
}
