"use client";

import { 
  Type, 
  Image as ImageIcon, 
  Shapes, 
  Sparkles, 
  Layers, 
  MousePointer2,
  Hand,
  Settings,
  Plus
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useEditor } from "./EditorContext";

export default function Sidebar() {
  const { addText, addImage, activeTab, setActiveTab } = useEditor();

  const tools = [
    { id: "select", icon: MousePointer2, label: "Select" },
    { id: "text", icon: Type, label: "Add Text" },
    { id: "image", icon: ImageIcon, label: "Add Image" },
    { id: "shape", icon: Shapes, label: "Shapes" },
    { id: "ai", icon: Sparkles, label: "AI Generator", highlight: true },
    { id: "layers", icon: Layers, label: "Layers" },
  ] as const;

  return (
    <aside className="flex w-16 flex-col items-center border-r border-zinc-200 bg-white py-4 dark:border-zinc-800 dark:bg-zinc-950 z-20">
      <div className="flex flex-1 flex-col gap-4">
        {tools.map((tool) => (
          <button
            key={tool.id}
            title={tool.label}
            onClick={() => setActiveTab(tool.id)}
            className={cn(
              "group relative flex size-10 items-center justify-center rounded-xl transition-all",
              activeTab === tool.id
                ? "bg-zinc-900 text-white dark:bg-zinc-100 dark:text-zinc-950"
                : tool.highlight 
                  ? "bg-indigo-50 text-indigo-600 hover:bg-indigo-100 dark:bg-indigo-500/10 dark:text-indigo-400 dark:hover:bg-indigo-500/20"
                  : "text-zinc-500 hover:bg-zinc-100 hover:text-zinc-900 dark:text-zinc-400 dark:hover:bg-zinc-900 dark:hover:text-zinc-100"
            )}
          >
            <tool.icon className="size-5" />
            
            {/* Tooltip */}
            <div className="absolute left-14 hidden rounded-md bg-zinc-900 px-2 py-1 text-xs text-white group-hover:block dark:bg-zinc-100 dark:text-zinc-950 shadow-xl whitespace-nowrap z-50">
              {tool.label}
            </div>
          </button>
        ))}
      </div>
      
      <button className="flex size-10 items-center justify-center rounded-xl text-zinc-500 hover:bg-zinc-100 hover:text-zinc-900 dark:text-zinc-400 dark:hover:bg-zinc-900 dark:hover:text-zinc-100">
        <Settings className="size-5" />
      </button>
    </aside>
  );
}
